const days=['domingo','segunda','terça','quarta','quinta','sexta','sábado'];
const now=new Date(new Date().toLocaleString('en-US',{timeZone:'America/Sao_Paulo'}));
const pad=n=>String(n).padStart(2,'0');

const horaAtual=`${pad(now.getHours())}:${pad(now.getMinutes())}`;
const dataAtual=`${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

let r=`Agora são ${horaAtual} de ${days[now.getDay()]} ${pad(now.getDate())}/${pad(now.getMonth()+1)}/${String(now.getFullYear()).slice(2)}.\n`;
r+=`Timezone: America/Sao_Paulo (UTC-03:00)\n\n`;

for(let i=1;i<=6;i++){
  const f=new Date(now); f.setDate(now.getDate()+i);
  const iso=`${f.getFullYear()}-${pad(f.getMonth()+1)}-${pad(f.getDate())}`;
  if(i===1) r+=`Amanhã é ${days[f.getDay()]} ${pad(f.getDate())}/${pad(f.getMonth()+1)} → ${iso}\n`;
  else if(i===2) r+=`Depois de amanhã é ${days[f.getDay()]} ${pad(f.getDate())}/${pad(f.getMonth()+1)} → ${iso}\n`;
  else r+=`A próxima ${days[f.getDay()]} será dia ${pad(f.getDate())}/${pad(f.getMonth()+1)} → ${iso}\n`;
}
return [{json:{resultado:r.trim()}}];

